import axios from '../utils/axiosConfig';

const API_BASE_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000/api';

export const collaborativeFilterService = {
  // Get collaborative filtering recommendations for a user
  getUserRecommendations: async (userId, limit = 6) => {
    try {
      const response = await axios.get(`${API_BASE_URL}/collaborative/user/${userId}`, {
        params: { limit }
      });
      return response.data;
    } catch (error) {
      console.error('Error fetching collaborative recommendations:', error);
      throw error;
    }
  },

  // Submit a rating for a movie
  submitRating: async (userId, movieId, rating) => {
    try {
      const response = await axios.post(`${API_BASE_URL}/collaborative/ratings`, {
        userId,
        movieId,
        rating
      });
      return response.data;
    } catch (error) {
      console.error('Error submitting rating:', error);
      throw error;
    }
  },

  // Get all ratings for a user
  getUserRatings: async (userId) => {
    try {
      const response = await axios.get(`${API_BASE_URL}/collaborative/ratings/user/${userId}`);
      return response.data;
    } catch (error) {
      console.error('Error fetching user ratings:', error);
      throw error;
    }
  },

  // Get all ratings for a movie
  getMovieRatings: async (movieId) => {
    try {
      const response = await axios.get(`${API_BASE_URL}/collaborative/ratings/movie/${movieId}`);
      return response.data;
    } catch (error) {
      console.error('Error fetching movie ratings:', error);
      throw error;
    }
  }
};
